const videos = $json.videos || [];
if (!videos.length) {
  throw new Error('Aucune video Pexels retournee');
}
const preferred = [];
const fallback = [];
for (const video of videos) {
  for (const file of video.video_files || []) {
    if (!file?.link || file.file_type !== 'video/mp4') continue;
    const width = Number(file.width || video.width || 0);
    const height = Number(file.height || video.height || 0);
    if (!width || !height || height <= width) continue;
    const item = { link: file.link, width, height };
    if ((width === 1080 && height === 1920) || (width === 720 && height === 1280) || (width === 540 && height === 960)) {
      preferred.push(item);
    } else {
      fallback.push(item);
    }
  }
}
const pick = (preferred[0] || fallback.sort((a, b) => (b.height * b.width) - (a.height * a.width))[0]);
if (!pick) {
  throw new Error('Aucune video portrait exploitable retournee par Pexels');
}
return [{ json: {
  id: $('Set Input').item.json.contentIdeaId,
  workflowRunId: $('Set Input').item.json.workflowRunId,
  topic: $('Set Input').item.json.topic,
  scripts: $('Set Input').item.json.script,
  caption: $('Set Input').item.json.caption,
  image_prompt: String($('HTTP Request Image Prompt').item.json.choices?.[0]?.message?.content || '').trim(),
  background_video_url: pick.link
}}];

const http = require('http');
const https = require('https');
const { URL } = require('url');
const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Set Input').item.json.workflowRunId || 0);
if (!baseUrl) throw new Error('APP_VIDEO_OPS_BACKEND_BASE_URL manquante');
if (!callbackSecret) throw new Error('APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET manquante');
if (!workflowRunId) throw new Error('workflowRunId manquant');
const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: "Render Shotstack demande.",
  responsePayload: JSON.stringify({ contentIdeaId: Number($('Set Input').item.json.contentIdeaId || 0), shotstackRenderId: $('HTTP Request Shotstack Render').item.json.response?.id || $('HTTP Request Shotstack Render').item.json.id || '' }),
});
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
let response = null;
let lastError = null;
for (let attempt = 1; attempt <= 6; attempt += 1) {
  try {
    response = await new Promise((resolve, reject) => {
      const req = client.request({
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        path: url.pathname + url.search,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(body),
          'X-Video-Ops-Callback-Secret': callbackSecret,
        },
      }, (res) => {
        let data = '';
        res.on('data', (chunk) => { data += chunk; });
        res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });
    if (response.statusCode >= 200 && response.statusCode < 300) {
      break;
    }
    lastError = 'Callback backend refuse: ' + response.statusCode + ' ' + response.body;
    if (response.statusCode !== 404 || attempt === 6) {
      throw new Error(lastError);
    }
  } catch (error) {
    lastError = error.message || String(error);
    if (attempt === 6) {
      throw error;
    }
  }
  await sleep(500 * attempt);
}
if (!response || response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error(lastError || 'Callback backend refuse.');
}
return [{ json: { ...$json, callbackStatusCode: response.statusCode } }];
